css:
.loader {color: var(--loader-color, #ca8a04);
  --loader-secondary-color: #fde047;
  --loader-bg: #ffffff;
   width: 80px;
   height: 40px;
   background: radial-gradient(circle 11px at top,#0000 94%,var(--loader-secondary-color, #fde047)) 0 20px, radial-gradient(circle 11px at top,#0000 94%,var(--loader-secondary-color, #fde047)) 0 10px, radial-gradient(circle 11px at top,#0000 94%,var(--loader-secondary-color, #fde047)) 0 0 ;
   background-size: 20px 100%;
   background-repeat: repeat-x;
   animation: l7 1s infinite linear;
}
@keyframes l7  {
  50% {background-position: 10px 15px,-10px 12px,15px 8px}
100% {background-position: 20px 20px,-20px 10px,20px 0px}
}
